TriggerOraclev10g.body:
DECLARE envbq_status number; valor_envbq_update number; vro_error tkr_errores%ROWTYPE; BEGIN -- En el caso de INSERT IF INSERTING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_ENCUESTA_PACIENTE WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_ENCUESTA_PACIENTE WHERE ID = :NEW.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_ENCUESTA_PACIENTE ( ENVIO_BQ, ID, ID_CITA, RECOMIENDA_SERVICIO, PUDO_RESOLVER, SATISFACION_MEDICO, EXPERIMENTO_DIFICULTAD, OTRA_DIFICULTAD, COMENTARIOS, RATING, VISIBLE, COMENTARIOS_PRIVADOS, FECHA_ENCUESTA, NO_USAR_SERVICIO, RECOMENDACIONES_CLARA, FECHA_CREACION ) VALUES ( 0, -- ENVIO_BQ por defecto :NEW.ID, :NEW.ID_CITA, :NEW.RECOMIENDA_SERVICIO, :NEW.PUDO_RESOLVER, :NEW.SATISFACION_MEDICO, :NEW.EXPERIMENTO_DIFICULTAD, :NEW.OTRA_DIFICULTAD, :NEW.COMENTARIOS, :NEW.RATING, :NEW.VISIBLE, :NEW.COMENTARIOS_PRIVADOS, :NEW.FECHA_ENCUESTA, :NEW.NO_USAR_SERVICIO, :NEW.RECOMENDACIONES_CLARA, :NEW.FECHA_CREACION ); END IF;
-- En el caso de UPDATE IF UPDATING THEN SELECT (SELECT ENVIO_BQ FROM TKRBQ_ENCUESTA_PACIENTE WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NULL THEN
INSERT INTO TKRBQ_ENCUESTA_PACIENTE ( ENVIO_BQ, ID, ID_CITA, RECOMIENDA_SERVICIO, PUDO_RESOLVER, SATISFACION_MEDICO, EXPERIMENTO_DIFICULTAD, OTRA_DIFICULTAD, COMENTARIOS, RATING, VISIBLE, COMENTARIOS_PRIVADOS, FECHA_ENCUESTA, NO_USAR_SERVICIO, RECOMENDACIONES_CLARA, FECHA_CREACION ) VALUES ( 2, -- ENVIO_BQ por defecto :NEW.ID, :NEW.ID_CITA, :NEW.RECOMIENDA_SERVICIO, :NEW.PUDO_RESOLVER, :NEW.SATISFACION_MEDICO, :NEW.EXPERIMENTO_DIFICULTAD, :NEW.OTRA_DIFICULTAD, :NEW.COMENTARIOS, :NEW.RATING, :NEW.VISIBLE, :NEW.COMENTARIOS_PRIVADOS, :NEW.FECHA_ENCUESTA, :NEW.NO_USAR_SERVICIO, :NEW.RECOMENDACIONES_CLARA, :NEW.FECHA_CREACION );
ELSE IF envbq_status = 0 THEN valor_envbq_update := 0; ELSE valor_envbq_update := 2; END IF;
UPDATE TKRBQ_ENCUESTA_PACIENTE SET ENVIO_BQ = valor_envbq_update, ID = :NEW.ID, ID_CITA = :NEW.ID_CITA, RECOMIENDA_SERVICIO = :NEW.RECOMIENDA_SERVICIO, PUDO_RESOLVER = :NEW.PUDO_RESOLVER, SATISFACION_MEDICO = :NEW.SATISFACION_MEDICO, EXPERIMENTO_DIFICULTAD = :NEW.EXPERIMENTO_DIFICULTAD, OTRA_DIFICULTAD = :NEW.OTRA_DIFICULTAD, COMENTARIOS = :NEW.COMENTARIOS, RATING = :NEW.RATING, VISIBLE = :NEW.VISIBLE, COMENTARIOS_PRIVADOS = :NEW.COMENTARIOS_PRIVADOS, FECHA_ENCUESTA = :NEW.FECHA_ENCUESTA, NO_USAR_SERVICIO = :NEW.NO_USAR_SERVICIO, RECOMENDACIONES_CLARA = :NEW.RECOMENDACIONES_CLARA, FECHA_CREACION = :NEW.FECHA_CREACION WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF; END IF;
-- Caso DELETE IF DELETING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_ENCUESTA_PACIENTE WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_ENCUESTA_PACIENTE WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_ENCUESTA_PACIENTE ( ENVIO_BQ, ID, ID_CITA, RECOMIENDA_SERVICIO, PUDO_RESOLVER, SATISFACION_MEDICO, EXPERIMENTO_DIFICULTAD, OTRA_DIFICULTAD, COMENTARIOS, RATING, VISIBLE, COMENTARIOS_PRIVADOS, FECHA_ENCUESTA, NO_USAR_SERVICIO, RECOMENDACIONES_CLARA, FECHA_CREACION
) VALUES ( -1, -- ENVIO_BQ para DELETE :OLD.ID, :OLD.ID_CITA, :OLD.RECOMIENDA_SERVICIO, :OLD.PUDO_RESOLVER, :OLD.SATISFACION_MEDICO, :OLD.EXPERIMENTO_DIFICULTAD, :OLD.OTRA_DIFICULTAD, :OLD.COMENTARIOS, :OLD.RATING, :OLD.VISIBLE, :OLD.COMENTARIOS_PRIVADOS, :OLD.FECHA_ENCUESTA, :OLD.NO_USAR_SERVICIO, :OLD.RECOMENDACIONES_CLARA, :OLD.FECHA_CREACION ); END IF;
EXCEPTION WHEN OTHERS THEN vro_error.nombre_programa := 'TRG_SYNC_TKR_ENCUESTA_PACIENTE'; vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ'; vro_error.parametros := 'id de consultas: '||:old.id; uti_ge_excepciones_pkg.p_grabar_log (vro_error);
END;
